const { log } = require('../logger');

/**
 * @typedef { keyof typeof import('../../constants/device').DEVICE_TYPES } DeviceType
 * @typedef { import('../../page/http-error-page').HttpErrorPage } HttpErrorPage
 * @typedef { import('../../page/navigable-page').NavigablePage } NavigablePage
 *
 * @typedef { object } NoBaseViewForBaseStyleSheetData
 * @property { string } baseStyleSheet - StyleSheet of base paths
 * @property { DeviceType } device - Device choose to complete the base paths
 * @property { string } priorityDeviceView - Device choose to be assign to the base paths
 * @property { string } pageLogPortion - Log portion with the page identifier (ex. route or status error)
 *
 * @typedef { object } NoBasePathsFoundForPageData
 * @property { DeviceType } device - Device choose as base
 * @property { string } priorityDeviceView - Device choose to be assign as the base paths
 * @property { string } pageLogPortion - Log portion with the page identifier (ex. route or status error)
 */

/**
 * @param { string } styleSheet - StyleSheet path
 * @returns { string } StyleSheet inconsistency log base
 */
const getStyleSheetInconsistencyLogBase = (styleSheet) =>
  `The style sheet ${styleSheet} does not match any view`;

/**
 * @param { string } styleSheet - StyleSheet that brings the inconsistency
 * @param { string } pageLogPortion - Log portion with the page identifier (ex. route or status error)
 * @returns { string } StyleSheet inconsistency log base
 */
const getNoPageViewExistsForBaseStyleSheetLog = (styleSheet, pageLogPortion) =>
  `${getStyleSheetInconsistencyLogBase(
    styleSheet,
  )}. Please move it to the style components folder ` +
  'or create the corresponding view following the naming ' +
  `convention for the ${pageLogPortion}`;

/**
 * @param { NoBaseViewForBaseStyleSheetData } noBaseViewForBaseStyleSheetData
 * @returns { string } No base view for base style sheet log
 */
const getNoBaseViewForBaseStyleSheetLog = ({
  baseStyleSheet,
  device,
  priorityDeviceView,
  pageLogPortion,
}) =>
  `${getStyleSheetInconsistencyLogBase(
    baseStyleSheet,
  )} and now is asociated with the following ${device} ` +
  `device type view: ${priorityDeviceView}. Please create the ` +
  'corresponding base view following the naming convention for ' +
  `the ${pageLogPortion}`;

/**
 * @param { NoBasePathsFoundForPageData } noBasePathsFoundForPageData
 * @returns { string } No base paths found log
 */
const getNoBasePathsFoundForPageLog = ({
  device,
  priorityDeviceView,
  pageLogPortion,
}) =>
  `The following ${pageLogPortion} does not match any base view, ` +
  `so the ${device} device type view will be considered as the base ` +
  `view: ${priorityDeviceView}. Please create the corresponding base ` +
  `view following the naming convention for the ${pageLogPortion}`;

/**
 * @param { string } styleSheet - Device style sheet that brings the inconsistency
 * @returns { string } No base view for device style sheet log
 */
const getNoBaseViewForDeviceStyleSheetLog = (styleSheet) =>
  `${getStyleSheetInconsistencyLogBase(
    styleSheet,
  )}. Please check the naming convention of the view for ` +
  'different device types or create the base view.';

/**
 * @param { NavigablePage | HttpErrorPage } page
 */
const informInvalidPaths = (page) => {
  const invalidPaths = page.getAllFilesOfPage();

  if (!invalidPaths.length) {
    return;
  }

  log.warn(
    `The following paths could not be processed correctly:\n- ${invalidPaths.join(
      '\n- ',
    )}`,
  );
};

/**
 * @param { NavigablePage | HttpErrorPage } previousPage - Page assign previously with the same identifier as the new page (ex. route or status error)
 * @param { NavigablePage | HttpErrorPage } currentPage - New page that brings the inconsistency
 * @return { string[] } Files of duplicated pages
 */
const getDuplicatedPageFiles = (previousPage, currentPage) => {
  const duplicatedFiles = [];

  duplicatedFiles.push(previousPage.getAllFilesOfPage());
  duplicatedFiles.push(currentPage.getAllFilesOfPage());

  return duplicatedFiles.flat();
};

module.exports = {
  getStyleSheetInconsistencyLogBase,
  getNoPageViewExistsForBaseStyleSheetLog,
  getNoBaseViewForBaseStyleSheetLog,
  getNoBasePathsFoundForPageLog,
  getNoBaseViewForDeviceStyleSheetLog,
  informInvalidPaths,
  getDuplicatedPageFiles,
};
